class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

def sublist_search(main_list_head: Node, sub_list_head: Node) -> bool:
    if sub_list_head is None:
        return True

    if main_list_head is None:
        return False

    main_ptr_start = main_list_head

    while main_ptr_start is not None:
        ptr1 = main_ptr_start
        ptr2 = sub_list_head

        while ptr1 is not None and ptr2 is not None and ptr1.data == ptr2.data:
            ptr1 = ptr1.next
            ptr2 = ptr2.next

        if ptr2 is None:
            return True

        main_ptr_start = main_ptr_start.next

    return False
